/* -------------------------------------------------------------------- */

const VALUE_PROPS = [
  { icon: "sparkle", label: "Streamline Ops" },
  { icon: "heart", label: "Delight guests" },
  { icon: "chart", label: "Grow ROI" },
];

const INDUSTRIES = ["Restaurants", "Fast Food", "Hotels", "Lounges", "Clinics", "Events"];

function Icon({ name, size = 16 }) {
  const common = { width: size, height: size, viewBox: "0 0 24 24", fill: "none" };
  switch (name) {
    case "sparkle":
      return (
        <svg {...common}>
          <path d="M12 2l1.8 5.6L19.4 9.4 13.8 11.2 12 16.8 10.2 11.2 4.6 9.4 10.2 7.6 12 2z" fill="currentColor" />
        </svg>
      );
    case "heart":
      return (
        <svg {...common}>
          <path
            d="M12 20.5s-7.5-4.4-9.7-9.1C.8 8.1 2.4 4.8 5.9 4.2c2-.3 3.7.6 4.9 2.1 1.2-1.5 2.9-2.4 4.9-2.1 3.5.6 5.1 3.9 3.6 7.2-2.2 4.7-9.7 9.1-9.7 9.1z"
            fill="currentColor"
          />
        </svg>
      );
    case "chart":
      return (
        <svg {...common}>
          <path d="M3 17l5-6 4 3 6-8" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
          <path d="M14 6h4v4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      );
    case "mail":
      return (
        <svg {...common}>
          <rect x="3" y="5" width="18" height="14" rx="2" stroke="currentColor" strokeWidth="1.8" />
          <path d="M3.5 6.5l8.5 6 8.5-6" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />
        </svg>
      );
    case "google":
      return (
        <svg {...common} viewBox="0 0 18 18">
          <path d="M17.6 9.2c0-.6 0-1.2-.2-1.8H9v3.4h4.8c-.2 1.1-.9 2-1.9 2.7v2.2h3.1c1.8-1.7 2.6-4 2.6-6.5z" fill="#4285F4" />
          <path d="M9 18c2.4 0 4.5-.8 6-2.2l-3.1-2.2c-.8.6-1.9 1-2.9 1-2.2 0-4.1-1.5-4.8-3.5H1.1v2.3C2.6 16.3 5.6 18 9 18z" fill="#34A853" />
          <path d="M4.2 11.1c-.2-.6-.3-1.2-.3-1.9s.1-1.3.3-1.9V5H1.1A8.8 8.8 0 000 9.2c0 1.4.3 2.8 1.1 4l3.1-2.1z" fill="#FBBC05" />
          <path d="M9 3.7c1.3 0 2.5.5 3.4 1.3l2.7-2.6C13.5.9 11.4 0 9 0 5.6 0 2.6 1.7 1.1 4.2l3.1 2.3C4.9 4.5 6.8 3.7 9 3.7z" fill="#EA4335" />
        </svg>
      );
    case "apple":
      return (
        <svg {...common} fill="currentColor">
          <path d="M16.4 12.6c0-1.8.9-3.2 2.6-4.1-1-1.4-2.5-2.2-4.4-2.3-1.8-.1-3 1-3.8 1-.8 0-2.3-1-3.7-1-2.2 0-4.6 1.8-4.6 5.2 0 2 .4 4 1.2 5.5.7 1.5 2 3.5 3.5 3.4 1.1 0 1.5-.7 2.9-.7s1.7.7 2.9.7c1.4 0 2.7-1.9 3.4-3.3-2.2-1-3-2.6-3-4.4zM13.4 4c.6-.8 1-1.9 1-3-1.1.1-2.4.8-3.1 1.6-.6.7-1.1 1.8-1 2.9 1.2.1 2.4-.6 3.1-1.5z" />
        </svg>
      );
    case "star":
      return (
        <svg {...common} fill="currentColor">
          <path d="M12 2.5l2.6 5.4 5.9.8-4.3 4.2 1 5.9L12 16l-5.2 2.8 1-5.9-4.3-4.2 5.9-.8L12 2.5z" />
        </svg>
      );
    case "back":
      return (
        <svg {...common}>
          <path d="M14.5 5.5L8 12l6.5 6.5" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      );
    case "forward":
      return (
        <svg {...common}>
          <path d="M9.5 5.5L16 12l-6.5 6.5" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      );
    default:
      return null;
  }
}

